    // Função para mostrar notificação toast (simples e rápida)
    // Suporta:
    // - showToast('Mensagem', 2000)
    // - showToast('Mensagem', 'success'|'error'|'info', 2000)
    function showToast(message, variantOrDuration = 2000, maybeDuration) {
        const text = String(message || '').trim();

        let variant = 'info';
        let duration = 2000;
        if (typeof variantOrDuration === 'number') {
            duration = variantOrDuration;
        } else if (typeof variantOrDuration === 'string') {
            variant = variantOrDuration;
            duration = (typeof maybeDuration === 'number' && Number.isFinite(maybeDuration)) ? maybeDuration : 2000;
        }

        // Remover toast anterior se existir
        const existingToast = document.getElementById('customToast');
        if (existingToast) {
            try { existingToast.remove(); } catch (_) {}
        }

        const toast = document.createElement('div');
        toast.id = 'customToast';
        toast.className = `custom-toast custom-toast-${variant}`;

        const icon = document.createElement('div');
        icon.className = 'custom-toast-icon';
        if (variant === 'success') {
            icon.innerHTML = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M20 6L9 17l-5-5"></path></svg>`;
        } else if (variant === 'error') {
            icon.innerHTML = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M18 6L6 18"></path><path d="M6 6l12 12"></path></svg>`;
        } else if (variant === 'warn' || variant === 'warning') {
            icon.innerHTML = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"></path><path d="M12 9v4"></path><path d="M12 17h.01"></path></svg>`;
        } else {
            icon.innerHTML = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 18h.01"></path><path d="M12 14a4 4 0 0 0-4-4"></path><path d="M12 2a10 10 0 1 0 10 10A10 10 0 0 0 12 2z"></path></svg>`;
        }

        const msg = document.createElement('div');
        msg.className = 'custom-toast-text';
        msg.textContent = text || (variant === 'success' ? 'Confirmado' : variant === 'error' ? 'Erro' : 'Aviso');

        toast.appendChild(icon);
        toast.appendChild(msg);
        document.body.appendChild(toast);

        // Mostrar com animação
        setTimeout(() => toast.classList.add('show'), 10);

        // Remover após duração
        setTimeout(() => {
            toast.classList.remove('show');
            setTimeout(() => {
                try { toast.remove(); } catch (_) {}
            }, 300);
        }, duration);
    }

    // ═══════════════════════════════════════════════════════════════
    // ⚪ ALERTAS DO BRANCO — Notificação premium (estilo "Bunny"/cadastro)
    // - Card branco, logo centralizada, título + detalhes
    // - Sem backdrop (não atrapalha o uso)
    // - Auto-hide em 5s (pedido do usuário)
    // ═══════════════════════════════════════════════════════════════
    let daWhiteAlertToastEl = null;
    let daWhiteAlertToastTimer = null;
    let daWhiteAlertToastPaused = false;
    let daWhiteAlertToastDeadline = 0;
    let daWhiteAlertToastRemainingMs = 0;
    let daWhiteAlertToastRepositionBound = false;

    function getWhiteAlertToastAnchorEl() {
        try {
            // ✅ Âncora: card "Padrão / Últimos giros" (lado direito).
            // O toast deve cobrir EXATAMENTE essa área (sem sair da tela).
            const root = document.getElementById('blaze-double-analyzer') || document.body;
            const candidates = [
                '#blaze-double-analyzer #analyzerDefaultView .pattern-section.da-card',
                '#blaze-double-analyzer #analyzerDefaultView .pattern-section',
                '#blaze-double-analyzer #patternInfo',
                '#patternInfo'
            ];
            for (const sel of candidates) {
                const el = root.querySelector ? root.querySelector(sel) : document.querySelector(sel);
                if (!el) continue;
                const r = el.getBoundingClientRect ? el.getBoundingClientRect() : null;
                if (r && r.width > 80 && r.height > 80) return el;
            }
        } catch (_) {}
        return null;
    }

    function getWhiteAlertToastAnchorRect() {
        try {
            const el = getWhiteAlertToastAnchorEl();
            const r = el && el.getBoundingClientRect ? el.getBoundingClientRect() : null;
            return (r && r.width > 40 && r.height > 40) ? r : null;
        } catch (_) {}
        return null;
    }

    function positionWhiteAlertToastCard(el) {
        try {
            const wrap = el || daWhiteAlertToastEl || document.getElementById('daWhiteAlertToast');
            if (!wrap) return;
            const card = wrap.querySelector('.da-white-alert-toast__card');
            if (!card) return;
            if (wrap.style.display === 'none') return;
            // ✅ Garantir que o toast esteja dentro do card "Padrão" (sem sair da tela).
            const root = document.getElementById('blaze-double-analyzer') || document.body;
            const anchor = getWhiteAlertToastAnchorEl() || root;
            try {
                if (anchor && anchor !== document.body && typeof window !== 'undefined' && window.getComputedStyle) {
                    const cs = window.getComputedStyle(anchor);
                    if (cs && cs.position === 'static') anchor.style.position = 'relative';
                }
            } catch (_) {}
            try {
                if (wrap.parentNode !== anchor) anchor.appendChild(wrap);
            } catch (_) {}
        } catch (_) {}
    }

    function ensureWhiteAlertToastUI() {
        try {
            if (daWhiteAlertToastEl && document.contains(daWhiteAlertToastEl)) return daWhiteAlertToastEl;
            const existing = document.getElementById('daWhiteAlertToast');
            if (existing) {
                daWhiteAlertToastEl = existing;
                return existing;
            }

            const wrap = document.createElement('div');
            wrap.id = 'daWhiteAlertToast';
            wrap.className = 'da-white-alert-toast';
            wrap.style.display = 'none';
            wrap.innerHTML = `
                <div class="da-white-alert-toast__card" role="status" aria-live="polite">
                    <div class="da-profile-nudge__content da-white-alert-toast__content">
                        <div class="da-white-alert-toast__logo-wrap">
                            <img class="da-white-alert-toast__logo" id="daWhiteAlertToastLogo" alt="Double Análise" />
                        </div>
                        <div class="da-profile-nudge__hero">
                            <div class="da-profile-nudge__headline" id="daWhiteAlertToastTitle">Aviso</div>
                            <div class="da-profile-nudge__subtitle" id="daWhiteAlertToastSubtitle">Branco • Alertas</div>
                        </div>
                        <div class="da-profile-nudge__body">
                            <div class="da-profile-nudge__text">
                                <div class="da-profile-nudge__message" id="daWhiteAlertToastMessage">—</div>
                            </div>
                        </div>
                    </div>
                    <div class="da-profile-nudge__timer">
                        <div class="da-profile-nudge__timer-fill" id="daWhiteAlertToastTimerFill"></div>
                    </div>
                </div>
            `;

            const root = document.getElementById('blaze-double-analyzer') || document.body;
            const anchor = getWhiteAlertToastAnchorEl() || root;
            // Garantir que a âncora aceite position:absolute do overlay
            try {
                if (anchor && anchor !== document.body && typeof window !== 'undefined' && window.getComputedStyle) {
                    const cs = window.getComputedStyle(anchor);
                    if (cs && cs.position === 'static') anchor.style.position = 'relative';
                }
            } catch (_) {}
            anchor.appendChild(wrap);

            const card = wrap.querySelector('.da-white-alert-toast__card');

            // ✅ Pausar ao interagir (igual ao aviso de cadastro):
            // - Desktop: hover pausa; sair do hover resume
            // - Mobile: toque/click no card alterna pausa/resume
            const pause = () => pauseWhiteAlertToastAutoHide();
            const resume = () => resumeWhiteAlertToastAutoHide();

            if (card && !card.dataset.daBound) {
                card.dataset.daBound = '1';
                card.addEventListener('mouseenter', () => pause());
                card.addEventListener('mouseleave', () => resume());
                card.addEventListener('click', (e) => {
                    try { e.preventDefault(); } catch (_) {}
                    if (daWhiteAlertToastPaused) resume();
                    else pause();
                });
            }

            daWhiteAlertToastEl = wrap;

            return wrap;
        } catch (_) {
            return null;
        }
    }

    function pauseWhiteAlertToastAutoHide() {
        try {
            const el = daWhiteAlertToastEl || document.getElementById('daWhiteAlertToast');
            if (!el || el.style.display === 'none') return;
            if (daWhiteAlertToastPaused) return;
            daWhiteAlertToastPaused = true;
            const now = Date.now();
            const remaining = Math.max(0, (daWhiteAlertToastDeadline || now) - now);
            daWhiteAlertToastRemainingMs = remaining;
            if (daWhiteAlertToastTimer) {
                clearTimeout(daWhiteAlertToastTimer);
                daWhiteAlertToastTimer = null;
            }
            el.classList.add('is-paused');
        } catch (_) {}
    }

    function resumeWhiteAlertToastAutoHide() {
        try {
            const el = daWhiteAlertToastEl || document.getElementById('daWhiteAlertToast');
            if (!el || el.style.display === 'none') return;
            if (!daWhiteAlertToastPaused) return;
            daWhiteAlertToastPaused = false;
            const remaining = Math.max(0, Number(daWhiteAlertToastRemainingMs) || 0);
            daWhiteAlertToastDeadline = Date.now() + remaining;
            el.classList.remove('is-paused');
            if (daWhiteAlertToastTimer) {
                clearTimeout(daWhiteAlertToastTimer);
                daWhiteAlertToastTimer = null;
            }
            if (remaining > 0) {
                daWhiteAlertToastTimer = setTimeout(() => hideWhiteAlertToast(), remaining);
            }
        } catch (_) {}
    }

    function hideWhiteAlertToast() {
        try {
            const el = daWhiteAlertToastEl || document.getElementById('daWhiteAlertToast');
            if (!el) return;
            el.classList.remove('show');
            el.classList.remove('is-paused');
            setTimeout(() => {
                try { el.style.display = 'none'; } catch (_) {}
            }, 180);
            if (daWhiteAlertToastTimer) {
                clearTimeout(daWhiteAlertToastTimer);
                daWhiteAlertToastTimer = null;
            }
            daWhiteAlertToastPaused = false;
            daWhiteAlertToastDeadline = 0;
            daWhiteAlertToastRemainingMs = 0;
        } catch (_) {}
    }

    function showWhiteAlertToastCard({ title, subtitle, message, durationMs = 5000 } = {}) {
        try {
            const el = ensureWhiteAlertToastUI();
            if (!el) return;

            const titleEl = el.querySelector('#daWhiteAlertToastTitle');
            const subtitleEl = el.querySelector('#daWhiteAlertToastSubtitle');
            const msgEl = el.querySelector('#daWhiteAlertToastMessage');
            const logoEl = el.querySelector('#daWhiteAlertToastLogo');
            const fill = el.querySelector('#daWhiteAlertToastTimerFill');

            if (titleEl) titleEl.textContent = String(title || 'Aviso');
            if (subtitleEl) subtitleEl.innerHTML = String(subtitle || 'Branco • Alertas');
            if (msgEl) msgEl.textContent = String(message || '').trim() || '—';

            // Logo (usar asset local do frontend — leve e consistente)
            try {
                if (logoEl) {
                    // ✅ Usar a MESMA logo do header (cache da landing), para ficar consistente com o app
                    // (evita “trocar a marca” aqui e ficar diferente do resto).
                    const KEY = 'lp_brand_cache_v1';
                    const raw = localStorage.getItem(KEY);
                    const data = raw ? JSON.parse(raw) : null;
                    const logo = data && typeof data.logo === 'string' ? data.logo : '';
                    logoEl.src = logo || 'assets/logo-da-full.png';
                }
            } catch (_) {}

            // Reiniciar animação do timer
            if (fill) {
                try {
                    fill.classList.remove('is-running');
                    void fill.offsetWidth; // reflow
                    fill.style.setProperty('--da-profile-nudge-duration', `${Math.max(1000, Number(durationMs) || 5000)}ms`);
                    fill.classList.add('is-running');
                } catch (_) {}
            }

            el.style.display = 'block';
            // Reiniciar estado do timer (não pausado)
            daWhiteAlertToastPaused = false;
            el.classList.remove('is-paused');
            requestAnimationFrame(() => {
                el.classList.add('show');
            });

            if (daWhiteAlertToastTimer) clearTimeout(daWhiteAlertToastTimer);
            const dur = Math.max(1000, Number(durationMs) || 5000);
            daWhiteAlertToastRemainingMs = dur;
            daWhiteAlertToastDeadline = Date.now() + dur;
            daWhiteAlertToastTimer = setTimeout(() => hideWhiteAlertToast(), dur);
        } catch (_) {}
    }
    
    // ========= FEEDBACK GLOBAL DE SALVAR (CENTRO DA TELA) =========
    let saveStatusTimeout = null;
    
    function ensureSaveStatusOverlay() {
        let overlay = document.getElementById('saveStatusOverlay');
        if (!overlay) {
            overlay = document.createElement('div');
            overlay.id = 'saveStatusOverlay';
            overlay.className = 'save-status-overlay';
            overlay.innerHTML = `
                <div class="save-status-bubble">
                    <div class="save-status-spinner" id="saveStatusSpinner"></div>
                    <div class="save-status-check" id="saveStatusCheck" style="display:none;">
                        <div class="save-status-check-icon"></div>
                    </div>
                </div>
            `;
            document.body.appendChild(overlay);
        }
        return overlay;
    }
    
    function showGlobalSaveLoading() {
        const overlay = ensureSaveStatusOverlay();
        const spinner = document.getElementById('saveStatusSpinner');
        const check = document.getElementById('saveStatusCheck');
        if (!overlay || !spinner || !check) return;
        
        if (saveStatusTimeout) {
            clearTimeout(saveStatusTimeout);
            saveStatusTimeout = null;
        }
        
        spinner.style.display = 'block';
        check.style.display = 'none';
        overlay.style.display = 'flex';
    }
    
    function showGlobalSaveSuccess(durationMs = 1500) {
        const overlay = ensureSaveStatusOverlay();
        const spinner = document.getElementById('saveStatusSpinner');
        const check = document.getElementById('saveStatusCheck');
        if (!overlay || !spinner || !check) return;
        
        spinner.style.display = 'none';
        check.style.display = 'flex';
        overlay.style.display = 'flex';
        
        if (saveStatusTimeout) {
            clearTimeout(saveStatusTimeout);
        }
        saveStatusTimeout = setTimeout(() => {
            overlay.style.display = 'none';
            spinner.style.display = 'block';
            check.style.display = 'none';
        }, durationMs);
    }
    
    function sendRuntimeMessage(payload) {
        return new Promise(resolve => {
            if (!chrome?.runtime?.sendMessage) {
                resolve(null);
                return;
            }
            try {
                chrome.runtime.sendMessage(payload, response => {
                    if (chrome.runtime.lastError) {
                        console.warn('chrome.runtime.sendMessage falhou:', chrome.runtime.lastError.message);
                        resolve(null);
                    } else {
                        resolve(response);
                    }
                });
            } catch (error) {
                console.warn('Erro ao enviar mensagem runtime:', error);
                resolve(null);
            }
        });
    }

    async function pauseAnalysisForAutoBet(reason = 'Auto stop') {
        const normalizedReason = reason || 'Auto stop';
        if (!analyzerActive && analyzerAutoPausedReason === normalizedReason) {
            return;
        }
        const response = await sendRuntimeMessage({ action: 'SET_ANALYSIS_ENABLED', enabled: false, source: 'AUTO_BET_STOP' });
        if (response && response.status === 'ok') {
            analyzerAutoPausedReason = normalizedReason;
            updateAnalyzerToggleUI(false, { log: true, source: normalizedReason });
            await persistAnalyzerState(false);
            showToast(`${normalizedReason}. Análises pausadas automaticamente.`, 2600);
        }
    }

    async function syncAnalyzerToggleStatus() {
        const response = await sendRuntimeMessage({ action: 'GET_ANALYSIS_STATUS' });
        if (response && typeof response.enabled === 'boolean') {
            updateAnalyzerToggleUI(response.enabled);
            persistAnalyzerState(response.enabled);
            return;
        }
        updateAnalyzerToggleUI(true);
        persistAnalyzerState(true);
    }
    
    async function initializeAnalyzerToggleState() {
        try {
            const stored = await storageCompat.get(['analyzerConfig']);
            const config = stored?.analyzerConfig;
            if (config && typeof config.analysisEnabled === 'boolean') {
                const desiredState = config.analysisEnabled;
                updateAnalyzerToggleUI(desiredState);
                await sendRuntimeMessage({ action: 'SET_ANALYSIS_ENABLED', enabled: desiredState });
                return;
            }
        } catch (error) {
            console.warn('⚠️ Erro ao carregar estado da análise do storage:', error);
        }
        await syncAnalyzerToggleStatus();
    }

    function updateAnalyzerToggleUI(isActive, options = {}) {
        const previousState = analyzerActive;
        analyzerActive = !!isActive;
        const opts = options || {};
        const shouldLog = !!opts.log;
        const logSource = typeof opts.source === 'string' && opts.source.trim().length
            ? opts.source.trim()
            : 'Painel';
        
        const toggleBtn = document.getElementById('toggleAnalyzerBtn');
        if (!toggleBtn) return;
        toggleBtn.classList.toggle('active', analyzerActive);
        const label = toggleBtn.querySelector('.toggle-label');
        if (label) {
            label.textContent = analyzerActive ? 'Análise ativa' : 'Ativar análise';
        }
        toggleBtn.title = analyzerActive ? 'Desativar análises' : 'Ativar análises';
        
        if (shouldLog && previousState !== analyzerActive) {
            logAnalyzerToggleStatus(analyzerActive, logSource);
        }
    }

    async function handleAnalyzerToggle() {
        if (analyzerToggleBusy) return;
        analyzerToggleBusy = true;
        const toggleBtn = document.getElementById('toggleAnalyzerBtn');
        if (toggleBtn) toggleBtn.classList.add('loading');
        const targetState = !analyzerActive;
        try {
            const response = await sendRuntimeMessage({ action: 'SET_ANALYSIS_ENABLED', enabled: targetState });
            const success = response && response.status === 'ok';
            if (success) {
                updateAnalyzerToggleUI(targetState, { log: true, source: 'Botão "Ativar análise"' });
                await persistAnalyzerState(targetState);
                if (targetState) {
                    analyzerAutoPausedReason = null;
                }
                showToast(targetState ? 'Análises ativadas' : 'Análises pausadas', 1800);
            } else {
                showToast(targetState ? 'Não foi possível ativar as análises' : 'Não foi possível pausar as análises', 2200);
                await syncAnalyzerToggleStatus();
            }
        } finally {
            analyzerToggleBusy = false;
            if (toggleBtn) toggleBtn.classList.remove('loading');
        }
    }
    
