    // Configurar listeners do modal
    function setupCustomPatternModalListeners() {
        const modal = document.getElementById('customPatternModal');
        const closeBtn = document.getElementById('closeCustomPatternModal');
        const cancelBtn = document.getElementById('cancelCustomPattern');
        const saveBtn = document.getElementById('saveCustomPattern');
        const addColorBtn = document.getElementById('addColorToSequence');
        const overlay = modal.querySelector('.custom-pattern-modal-overlay');
        
        // Fechar modal
        closeBtn.addEventListener('click', () => closeCustomPatternModal());
        cancelBtn.addEventListener('click', () => closeCustomPatternModal());
        overlay.addEventListener('click', () => closeCustomPatternModal());
        
        // Adicionar cor à sequência
        addColorBtn.addEventListener('click', () => showColorPicker());
        
        // Salvar modelo
        saveBtn.addEventListener('click', () => saveCustomPatternModel());
        
        // Botão "Adicionar Modelo" na sidebar
        setTimeout(() => {
            const btnAdd = document.getElementById('btnAddCustomPattern');
            if (btnAdd) {
                btnAdd.addEventListener('click', () => openCustomPatternModal());
            }
            
            // Botão "Ver Padrões Ativos"
            const btnView = document.getElementById('btnViewCustomPatterns');
            if (btnView) {
                btnView.addEventListener('click', () => {
                    const modal = document.getElementById('viewPatternsModal');
                    if (modal) {
                        modal.style.display = 'flex';
                        
                        // ✅ CENTRALIZAR MODAL COM BASE NA POSIÇÃO DA EXTENSÃO (com delay para renderização)
                        setTimeout(() => {
                            const sidebar = document.getElementById('blaze-double-analyzer');
                            if (sidebar) {
                                const rect = sidebar.getBoundingClientRect();
                                const modalContent = modal.querySelector('.custom-pattern-modal-content');
                                
                                if (modalContent) {
                                    // Centralizar horizontalmente com a sidebar
                                    const sidebarCenterX = rect.left + (rect.width / 2);
                                    const modalWidth = modalContent.offsetWidth || 500;
                                    let leftPosition = sidebarCenterX - (modalWidth / 2);
                                    
                                    // Garantir que o modal não saia da tela
                                    const margin = 20;
                                    if (leftPosition < margin) leftPosition = margin;
                                    if (leftPosition + modalWidth > window.innerWidth - margin) {
                                        leftPosition = window.innerWidth - modalWidth - margin;
                                    }
                                    
                                    // Centralizar verticalmente na tela
                                    const modalHeight = modalContent.offsetHeight || 400;
                                    let topPosition = (window.innerHeight - modalHeight) / 2;
                                    if (topPosition < margin) topPosition = margin;
                                    
                                    modalContent.style.left = leftPosition + 'px';
                                    modalContent.style.top = topPosition + 'px';
                                    modalContent.style.transform = 'none';
                                }
                            }
                        }, 10);
                    }
                });
            }
            
        }, 100);
    }
    
    // Abrir modal
    function openCustomPatternModal() {
        const modal = document.getElementById('customPatternModal');
        // 🖥️ Desktop (Dashboard novo): modal acoplado no workspace (lado direito)
        dockModalToDesktopWorkspace(modal);
        modal.style.display = 'flex';
        
        // Resetar campos
        document.getElementById('customPatternName').value = '';
        document.getElementById('customPatternSequence').innerHTML = '';
        document.querySelectorAll('input[name="beforeColor"]').forEach(radio => {
            radio.checked = radio.value === 'red-white'; // ✅ Padrão: Vermelho ou Branco
        });
        
        // ✅ Carregar preferência de sincronização
        const syncCheckbox = document.getElementById('syncPatternToAccount');
        if (syncCheckbox) {
            syncCheckbox.checked = getSyncPatternPreference();
            console.log(`🔄 Preferência de sincronização carregada: ${syncCheckbox.checked ? 'ATIVADA' : 'DESATIVADA'}`);
        }
        
        console.log('🎯 Modal de padrão customizado aberto');
    }
    
    // Fechar modal
    function closeCustomPatternModal() {
        const modal = document.getElementById('customPatternModal');
        modal.style.display = 'none';
        
        // Resetar botão de salvar (remover modo edição)
        const saveBtn = document.getElementById('saveCustomPattern');
        if (saveBtn) {
            saveBtn.textContent = '💾 Salvar Modelo';
            saveBtn.removeAttribute('data-editing-id');
        }
        
        console.log('❌ Modal de padrão customizado fechado');
    }
    
    // Mostrar seletor de cor
    function showColorPicker() {
        const sequenceDiv = document.getElementById('customPatternSequence');
        
        // Criar popup temporário para escolher cor (com quadradinhos visuais)
        const colorPickerHTML = `
            <div class="color-picker-popup">
                <button class="color-choice-visual red" data-color="red">
                    <span class="spin-color-circle red"></span>
                </button>
                <button class="color-choice-visual black" data-color="black">
                    <span class="spin-color-circle black"></span>
                </button>
                <button class="color-choice-visual white" data-color="white">
                    <span class="spin-color-circle white"></span>
                </button>
            </div>
        `;
        
        const tempDiv = document.createElement('div');
        tempDiv.innerHTML = colorPickerHTML;
        const popup = tempDiv.firstElementChild;
        
        // Posicionar popup
        sequenceDiv.appendChild(popup);
        
        // Event listeners para escolha de cor
        popup.querySelectorAll('.color-choice-visual').forEach(btn => {
            btn.addEventListener('click', () => {
                const color = btn.dataset.color;
                addColorToSequence(color);
                popup.remove();
            });
        });
    }
    
    // Adicionar cor à sequência
    function addColorToSequence(color) {
        const sequenceDiv = document.getElementById('customPatternSequence');
        
        const colorBadge = document.createElement('div');
        colorBadge.className = `sequence-color-item ${color}`;
        colorBadge.dataset.color = color;
        colorBadge.innerHTML = `<span class="spin-color-circle-small ${color}"></span>`;
        
        // Adicionar evento de clique para remover (ao invés de botão visível)
        colorBadge.addEventListener('click', function() {
            this.remove();
        });
        
        sequenceDiv.appendChild(colorBadge);
        
        console.log(`➕ Cor ${color} adicionada à sequência`);
    }
    
    // ═══════════════════════════════════════════════════════════════
    // 🌐 API HELPER - SINCRONIZAÇÃO COM SERVIDOR
      // ═══════════════════════════════════════════════════════════════
      // 🔧 AUTO-DISCOVERY SYSTEM - Busca URLs automaticamente do servidor
      // ═══════════════════════════════════════════════════════════════
      
      const URLS_LOCAL_KEY = 'da_urls_v1';
      
      // Fallback (primeiro acesso/sem cache). Depois do primeiro sync, vem do banco via /api/site/urls.
      const FALLBACK_ORIGINS = {
          auth: [
              'https://blaze-analyzer-api-v2-p9xb.onrender.com',
              'https://blaze-analyzer-api-v2-z8s3.onrender.com',
              'https://blaze-analyzer-api-v2.onrender.com'
          ],
          giros: [
              'https://blaze-giros-api-v2-7t0l.onrender.com',
              'https://blaze-giros-api-v2-1.onrender.com'
          ]
      };
      
      const API_URLS = {
          giros: window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
              ? 'http://localhost:3001'
              : FALLBACK_ORIGINS.giros[0],
          auth: window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
              ? 'http://localhost:3000'
              : FALLBACK_ORIGINS.auth[0]
      };

      function normalizeOrigin(raw) {
          const v = String(raw || '').trim();
          if (!v) return '';
          const withoutApi = v.replace(/\/api\/?$/i, '');
          return withoutApi.replace(/\/+$/, '');
      }

      function getCandidateAuthOrigins(cfg) {
          const activeId = String(cfg?.runtimeActiveServerId || cfg?.activeServerId || '').trim();
          let activeOrigin = '';
          if (activeId && Array.isArray(cfg?.servers)) {
              const activeServer = cfg.servers.find((s) => String(s?.id || s?.serverId || '').trim() === activeId);
              activeOrigin = normalizeOrigin(activeServer?.authOrigin);
          }
          const fromArray = Array.isArray(cfg?.authApiOrigins) ? cfg.authApiOrigins : [];
          const fromServers = Array.isArray(cfg?.servers) ? cfg.servers.map((s) => s?.authOrigin) : [];
          const combined = [activeOrigin, ...fromArray, ...fromServers, ...FALLBACK_ORIGINS.auth]
              .map(normalizeOrigin)
              .filter(Boolean);
          return [...new Set(combined)];
      }
      
      // Busca URLs de um servidor específico
      async function fetchUrlsFrom(origin) {
          try {
              const url = `${origin}/api/site/urls`;
              const controller = (typeof AbortController !== 'undefined') ? new AbortController() : null;
              const timeoutId = controller ? setTimeout(() => controller.abort(), 5000) : null;

              const resp = await fetch(url, controller
                  ? { cache: 'no-store', signal: controller.signal }
                  : { cache: 'no-store' }
              ).finally(() => { if (timeoutId) clearTimeout(timeoutId); });
              if (!resp.ok) return null;
              const data = await resp.json();
              return data.success && data.urls ? data.urls : null;
          } catch (_) {
              return null;
          }
      }
      
      // Auto-Discovery: tenta todos os servidores conhecidos
      async function autoDiscoverUrls() {
          // Se for localhost, não fazer discovery
          if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
              return null;
          }
          
          let cached = null;
          try {
              const raw = localStorage.getItem(URLS_LOCAL_KEY);
              cached = raw ? JSON.parse(raw) : null;
          } catch (_) {}

          const candidates = getCandidateAuthOrigins(cached);
          for (const origin of candidates) {
              const urls = await fetchUrlsFrom(origin);
              if (urls) {
                  saveUrlsLocal(urls);
                  return urls;
              }
          }

          return null;
      }
      
      function saveUrlsLocal(urls) {
          try {
              const merged = {
                  authApiOrigins: Array.isArray(urls.authApiOrigins) ? urls.authApiOrigins.map(normalizeOrigin).filter(Boolean) : [],
                  girosApiOrigins: Array.isArray(urls.girosApiOrigins) ? urls.girosApiOrigins.map(normalizeOrigin).filter(Boolean) : [],
                  girosWsOrigins: Array.isArray(urls.girosWsOrigins) ? urls.girosWsOrigins.map((v) => String(v || '').trim()).filter(Boolean) : [],
                  servers: Array.isArray(urls.servers)
                      ? urls.servers.map((s) => ({
                          id: String(s?.id || '').trim(),
                          name: String(s?.name || '').trim(),
                          authOrigin: normalizeOrigin(s?.authOrigin),
                          girosOrigin: normalizeOrigin(s?.girosOrigin),
                          girosWsOrigin: String(s?.girosWsOrigin || '').trim(),
                          enabled: s?.enabled === false ? false : true
                      }))
                      : [],
                  activeServerId: String(urls.runtimeActiveServerId || urls.activeServerId || '').trim() || null,
                  runtimeActiveServerId: String(urls.runtimeActiveServerId || urls.activeServerId || '').trim() || null,
                  updatedAt: urls.updatedAt || null
              };
              if (merged.authApiOrigins.length || merged.girosApiOrigins.length || merged.girosWsOrigins.length) {
                  localStorage.setItem(URLS_LOCAL_KEY, JSON.stringify(merged));
              }

              // Na extensão, também tentar persistir em chrome.storage.local
              try {
                  if (typeof chrome !== 'undefined' && chrome.storage?.local?.set) {
                      chrome.storage.local.set({ [URLS_LOCAL_KEY]: merged }, () => {});
                  }
              } catch (_) {}
          } catch (_) {}
      }

      function applyRuntimeUrls(urls) {
          if (!urls || typeof urls !== 'object') return;
          const authList = Array.isArray(urls.authApiOrigins) ? urls.authApiOrigins : [];
          const girosList = Array.isArray(urls.girosApiOrigins) ? urls.girosApiOrigins : [];

          // ✅ Preferir servidor ativo (Admin Panel) quando disponível
          const activeId = String(urls.runtimeActiveServerId || urls.activeServerId || '').trim();
          const servers = Array.isArray(urls.servers) ? urls.servers : [];
          let activeServer = null;
          if (activeId && servers.length) {
              activeServer = servers.find((s) => {
                  const sid = String(s?.id || s?.serverId || '').trim();
                  return sid && sid === activeId;
              }) || null;
          }

          const nextAuth = normalizeOrigin(activeServer?.authOrigin) || normalizeOrigin(authList[0]);
          const nextGiros = normalizeOrigin(activeServer?.girosOrigin) || normalizeOrigin(girosList[0]);

          if (nextAuth) API_URLS.auth = nextAuth;
          if (nextGiros) API_URLS.giros = nextGiros;

          // Log leve para validar troca de servidor (ajuda a depurar “não atualizou”)
          try {
              if (activeId) {
                  console.log('🔧 [URLS] Servidor ativo aplicado no content:', {
                      activeServerId: activeId,
                      auth: API_URLS.auth,
                      giros: API_URLS.giros
                  });
              } else {
                  console.log('🔧 [URLS] URLs aplicadas no content:', { auth: API_URLS.auth, giros: API_URLS.giros });
              }
          } catch (_) {}
      }
      
      // Inicializa URLs automaticamente
      (async function initUrls() {
          // 1) Tenta localStorage primeiro (mais rápido)
          try {
              const raw = localStorage.getItem(URLS_LOCAL_KEY);
              if (raw) {
                  const parsed = JSON.parse(raw);
                  applyRuntimeUrls(parsed);
              }
          } catch (_) {}

          // 2) chrome.storage.local (principal na extensão)
          try {
              if (typeof chrome !== 'undefined' && chrome.storage?.local?.get) {
                  chrome.storage.local.get([URLS_LOCAL_KEY], (result) => {
                      try {
                          const parsed = result ? result[URLS_LOCAL_KEY] : null;
                          applyRuntimeUrls(parsed);
                      } catch (_) {}
                  });
              }
          } catch (_) {}
          
          // 3) Auto-Discovery assíncrono (background, não bloqueia)
          setTimeout(async () => {
              const urls = await autoDiscoverUrls();
              if (urls) {
                  applyRuntimeUrls(urls);
              }
          }, 0);
      })();

      // ✅ Troca de servidor em tempo real (Admin Panel):
      // quando `da_urls_v1` mudar no storage, atualizar as URLs do content.js e puxar histórico do servidor novo.
      try {
          if (typeof chrome !== 'undefined' && chrome.storage?.onChanged?.addListener) {
              chrome.storage.onChanged.addListener((changes, areaName) => {
                  try {
                      if (areaName !== 'local') return;
                      if (!changes || !changes[URLS_LOCAL_KEY]) return;
                      const next = changes[URLS_LOCAL_KEY].newValue || null;
                      applyRuntimeUrls(next);
                      // Se está sem histórico (ou veio de servidor antigo), forçar refresh do histórico
                      try { updateHistoryUIFromServer(); } catch (_) {}
                  } catch (_) {}
              });
          }
      } catch (_) {}
      
      // Obter URL da API de Giros
      function getGirosApiUrl() {
          return API_URLS.giros;
      }
      
      // Obter URL da API de Auth (para compatibilidade com código antigo)
      function getApiUrl() {
          return API_URLS.auth;
      }

    // ═══════════════════════════════════════════════════════════════════════════════
    // 💾 ADAPTADOR DE STORAGE (chrome.storage.local ou fallback em localStorage)
    // ═══════════════════════════════════════════════════════════════════════════════

    const hasChromeStorage = typeof chrome !== 'undefined' &&
                             chrome?.storage &&
                             chrome.storage?.local;

    function deserializeFromLocalStorage(rawValue, fallbackValue = undefined) {
        if (rawValue === null || rawValue === undefined) return fallbackValue;
        try {
            return JSON.parse(rawValue);
        } catch (error) {
            console.warn('⚠️ Não foi possível converter valor do localStorage. Retornando bruto.', error);
            return rawValue;
        }
    }

    function serializeForLocalStorage(value) {
        try {
            return JSON.stringify(value);
        } catch (error) {
            console.error('❌ Não foi possível serializar valor para o localStorage:', error);
            return JSON.stringify(null);
        }
    }

    function fallbackStorageGet(request) {
        const result = {};

        if (Array.isArray(request)) {
            request.forEach((key) => {
                result[key] = deserializeFromLocalStorage(localStorage.getItem(key));
            });
        } else if (typeof request === 'string') {
            result[request] = deserializeFromLocalStorage(localStorage.getItem(request));
        } else if (request && typeof request === 'object') {
            Object.keys(request).forEach((key) => {
                const stored = localStorage.getItem(key);
                result[key] = stored === null || stored === undefined
                    ? request[key]
                    : deserializeFromLocalStorage(stored);
            });
        }

        return result;
    }

    function fallbackStorageSet(items) {
        if (!items || typeof items !== 'object') return;
        Object.entries(items).forEach(([key, value]) => {
            localStorage.setItem(key, serializeForLocalStorage(value));
        });
    }

    function fallbackStorageRemove(keys) {
        if (Array.isArray(keys)) {
            keys.forEach((key) => localStorage.removeItem(key));
        } else if (typeof keys === 'string') {
            localStorage.removeItem(keys);
        }
    }

    const storageCompat = {
        async get(request) {
            if (hasChromeStorage) {
                return await new Promise((resolve, reject) => {
                    try {
                        chrome.storage.local.get(request, (items) => {
                            const err = chrome.runtime?.lastError;
                            if (err) {
                                console.error('❌ Erro em chrome.storage.local.get:', err);
                                reject(new Error(err.message || err));
                            } else {
                                resolve(items);
                            }
                        });
                    } catch (error) {
                        reject(error);
                    }
                });
            }

            const fallback = fallbackStorageGet(request);
            return fallback;
        },

        async set(items) {
            if (hasChromeStorage) {
                return await new Promise((resolve, reject) => {
                    try {
                        chrome.storage.local.set(items, () => {
                            const err = chrome.runtime?.lastError;
                            if (err) {
                                console.error('❌ Erro em chrome.storage.local.set:', err);
                                reject(new Error(err.message || err));
                            } else {
                                resolve(true);
                            }
                        });
                    } catch (error) {
                        reject(error);
                    }
                });
            }

            fallbackStorageSet(items);
            return true;
        },

        async remove(keys) {
            if (hasChromeStorage) {
                return await new Promise((resolve, reject) => {
                    try {
                        chrome.storage.local.remove(keys, () => {
                            const err = chrome.runtime?.lastError;
                            if (err) {
                                console.error('❌ Erro em chrome.storage.local.remove:', err);
                                reject(new Error(err.message || err));
                            } else {
                                resolve(true);
                            }
                        });
                    } catch (error) {
                        reject(error);
                    }
                });
            }

            fallbackStorageRemove(keys);
            return true;
        }
    };

storageCompat.get(['analyzerConfig']).then(res => {
    latestAnalyzerConfig = res.analyzerConfig || null;
}).catch(() => {});

// ═══════════════════════════════════════════════════════════════════════════════
// 💎 ADMIN VISIBILITY (Diamond Levels)
// - Controle global: quais níveis do Diamante aparecem no site.
// - Fonte de verdade: GET /api/site/diamond-levels (público) + cache local.
// ═══════════════════════════════════════════════════════════════════════════════

const DIAMOND_VISIBLE_LEVELS_KEY = 'da_diamond_visible_levels_v1';
const DIAMOND_LEVEL_KEYS = ['n0','n1','n2','n3','n4','n5','n6','n7','n8','n9','n10'];

let diamondAdminVisibleLevels = null; // { n0:true, ... } | null

function normalizeDiamondVisibleLevelsMap(raw) {
    const base = {};
    DIAMOND_LEVEL_KEYS.forEach((k) => { base[k] = true; });
    if (Array.isArray(raw)) {
        const set = new Set(raw.map((v) => String(v || '').toLowerCase().trim()).filter(Boolean));
        DIAMOND_LEVEL_KEYS.forEach((k) => { base[k] = set.has(k); });
        return base;
    }
    if (raw && typeof raw === 'object') {
        DIAMOND_LEVEL_KEYS.forEach((k) => {
            if (Object.prototype.hasOwnProperty.call(raw, k)) base[k] = !!raw[k];
        });
        return base;
    }
    return base;
}

function diamondKeyFromIdLike(idLike) {
    const raw = String(idLike || '').trim();
    if (!raw) return '';
    const up = raw.toUpperCase();
    const m = up.match(/^N(\d+)$/);
    if (m) return `n${m[1]}`;
    const m2 = raw.toLowerCase().match(/^n(\d+)$/);
    if (m2) return `n${m2[1]}`;
    return raw.toLowerCase();
}

function isDiamondLevelVisibleByAdmin(idLike) {
    const key = diamondKeyFromIdLike(idLike);
    if (!key) return true;
    const map = diamondAdminVisibleLevels && typeof diamondAdminVisibleLevels === 'object' ? diamondAdminVisibleLevels : null;
    if (map && Object.prototype.hasOwnProperty.call(map, key)) return !!map[key];
    return true; // default: visível
}

function isDiamondLevelEnabledByUser(idLike, cfg = null) {
    try {
        const key = diamondKeyFromIdLike(idLike);
        if (!key) return true;

        const currentCfg = (cfg && typeof cfg === 'object') ? cfg : latestAnalyzerConfig;
        const enabledMap = currentCfg && currentCfg.diamondLevelEnabled && typeof currentCfg.diamondLevelEnabled === 'object'
            ? currentCfg.diamondLevelEnabled
            : null;
        if (!enabledMap) return true; // fallback seguro: sem config carregada, não ocultar

        if (Object.prototype.hasOwnProperty.call(enabledMap, key)) return !!enabledMap[key];
        const lower = key.toLowerCase();
        if (Object.prototype.hasOwnProperty.call(enabledMap, lower)) return !!enabledMap[lower];
        const upper = key.toUpperCase();
        if (Object.prototype.hasOwnProperty.call(enabledMap, upper)) return !!enabledMap[upper];

        return true;
    } catch (_) {
        return true;
    }
}

function shouldShowDiamondLevelInUi(idLike, cfg = null) {
    return isDiamondLevelVisibleByAdmin(idLike) && isDiamondLevelEnabledByUser(idLike, cfg);
}

function applyDiamondVisibleLevelsToDiamondLevelsModal() {
    try {
        const modal = document.getElementById('diamondLevelsModal');
        if (!modal) return;
        const body = modal.querySelector('.custom-pattern-modal-body');
        if (!body) return;

        const map = diamondAdminVisibleLevels && typeof diamondAdminVisibleLevels === 'object'
            ? diamondAdminVisibleLevels
            : null;
        if (!map) return;

        DIAMOND_LEVEL_KEYS.forEach((key) => {
            const visible = map[key] !== false;
            const num = String(key).replace(/^n/i, '');
            const upperId = `N${num}`;

            // Campo principal do nível
            const field = body.querySelector(`.diamond-level-field[data-level="${key}"]`);
            if (field) {
                field.style.display = visible ? '' : 'none';
            }

            // Toggle do nível (force-disable se oculto)
            const toggle = document.getElementById(`diamondLevelToggle${upperId}`);
            if (toggle) {
                toggle.disabled = !visible;
                if (!visible) toggle.checked = false;
            }

            // Dropdown de simulação (ocultar opção do nível)
            const simOption = body.querySelector(`.diamond-sim-option[data-level="${upperId}"]`);
            if (simOption) {
                simOption.style.display = visible ? '' : 'none';
            }
        });
    } catch (_) {}
}

function getDiamondEnabledDefaultsRespectingAdmin() {
    const base = { ...DIAMOND_LEVEL_ENABLE_DEFAULTS };
    const map = diamondAdminVisibleLevels && typeof diamondAdminVisibleLevels === 'object' ? diamondAdminVisibleLevels : null;
    if (!map) return base;
    DIAMOND_LEVEL_KEYS.forEach((k) => {
        base[k] = (map[k] !== false);
    });
    return base;
}

async function enforceDiamondEnabledMapAgainstAdminVisibility(options = {}) {
    const { sync = true } = options;
    try {
        const stored = await storageCompat.get(['analyzerConfig']);
        const current = (stored && stored.analyzerConfig && typeof stored.analyzerConfig === 'object') ? stored.analyzerConfig : {};
        const enabledIn = (current && current.diamondLevelEnabled && typeof current.diamondLevelEnabled === 'object')
            ? current.diamondLevelEnabled
            : null;

        const map = diamondAdminVisibleLevels && typeof diamondAdminVisibleLevels === 'object' ? diamondAdminVisibleLevels : null;
        if (!map) return null;

        const nextEnabled = {};
        DIAMOND_LEVEL_KEYS.forEach((k) => {
            const isVisible = map[k] !== false;
            const raw = enabledIn && Object.prototype.hasOwnProperty.call(enabledIn, k) ? !!enabledIn[k] : true;
            nextEnabled[k] = isVisible ? raw : false;
        });

        const same = (() => {
            try { return JSON.stringify(enabledIn || {}) === JSON.stringify(nextEnabled); } catch (_) { return false; }
        })();
        if (same) return current;

        // Persistir local (e sincronizar com servidor se permitido)
        const updated = await updateAnalyzerConfigPartial(
            { diamondLevelEnabled: nextEnabled, _clientUpdatedAt: Date.now() },
            { respectSyncPreference: sync }
        );
        try { latestAnalyzerConfig = updated || latestAnalyzerConfig; } catch (_) {}
        try { chrome.runtime.sendMessage({ action: 'applyConfig' }, function() {}); } catch (_) {}
        return updated;
    } catch (_) {
        return null;
    }
}

async function refreshDiamondVisibleLevelsFromServer() {
    try {
        const origin = (typeof getApiUrl === 'function') ? String(getApiUrl() || '').trim() : '';
        if (!origin) return null;
        const resp = await fetch(`${origin}/api/site/diamond-levels`, { cache: 'no-store' });
        if (!resp.ok) return null;
        const data = await resp.json().catch(() => null);
        if (!data || !data.success) return null;
        const normalized = normalizeDiamondVisibleLevelsMap(data.levels);
        await storageCompat.set({ [DIAMOND_VISIBLE_LEVELS_KEY]: normalized });
        return normalized;
    } catch (_) {
        return null;
    }
}

async function initDiamondVisibleLevels() {
    try {
        const stored = await storageCompat.get([DIAMOND_VISIBLE_LEVELS_KEY]);
        if (stored && stored[DIAMOND_VISIBLE_LEVELS_KEY]) {
            diamondAdminVisibleLevels = normalizeDiamondVisibleLevelsMap(stored[DIAMOND_VISIBLE_LEVELS_KEY]);
            applyDiamondVisibleLevelsToDiamondLevelsModal();
            // ✅ Garantia: nível oculto não fica ativo "por trás"
            enforceDiamondEnabledMapAgainstAdminVisibility({ sync: true }).catch(() => {});
        }
    } catch (_) {}

    // buscar do servidor sem bloquear a UI
    setTimeout(async () => {
        const fresh = await refreshDiamondVisibleLevelsFromServer();
        if (fresh) {
            diamondAdminVisibleLevels = fresh;
            applyDiamondVisibleLevelsToDiamondLevelsModal();
            enforceDiamondEnabledMapAgainstAdminVisibility({ sync: true }).catch(() => {});
        }
    }, 0);
}

// Inicializar (não bloqueia)
setTimeout(() => { initDiamondVisibleLevels(); }, 0);

const autoBetHistoryStore = (() => {
    let cache = [];
    let initialized = false;
    const listeners = new Set();

    async function init() {
        if (initialized) return cache;
        try {
            const stored = await storageCompat.get([AUTO_BET_HISTORY_KEY]);
            const raw = stored[AUTO_BET_HISTORY_KEY];
            cache = Array.isArray(raw) ? raw : [];
        } catch (error) {
            console.warn('AutoBetHistory: falha ao carregar histórico:', error);
            cache = [];
        }
        initialized = true;
        return cache;
    }

    function getSnapshot() {
        return cache.map(item => ({
            ...item,
            stages: Array.isArray(item.stages)
                ? item.stages.map(stage => ({ ...stage }))
                : []
        }));
    }

    function clamp() {
        if (cache.length > AUTO_BET_HISTORY_LIMIT) {
            cache = cache.slice(0, AUTO_BET_HISTORY_LIMIT);
        }
    }

    function persist() {
        storageCompat.set({ [AUTO_BET_HISTORY_KEY]: cache })
            .catch(err => console.warn('AutoBetHistory: falha ao salvar histórico:', err));
    }

    function notify() {
        const snapshot = getSnapshot();
        listeners.forEach(listener => {
            try {
                listener(snapshot);
            } catch (error) {
                console.warn('AutoBetHistory: listener falhou:', error);
            }
        });
    }

    function upsert(record) {
        if (!record || !record.id) return;
        const nextRecord = {
            status: 'pending',
            stages: [],
            createdAt: Date.now(),
            totalColorInvested: 0,
            totalWhiteInvested: 0,
            ...record
        };
        const idx = cache.findIndex(item => item.id === nextRecord.id);
        if (idx >= 0) {
            cache[idx] = { ...cache[idx], ...nextRecord };
        } else {
            cache.unshift(nextRecord);
        }
        clamp();
        persist();
        notify();
    }

    function patch(id, updater) {
        if (!id || typeof updater !== 'function') return;
        const idx = cache.findIndex(item => item.id === id);
        if (idx === -1) return;
        const current = cache[idx];
        const draft = {
            ...current,
            stages: Array.isArray(current.stages)
                ? current.stages.map(stage => ({ ...stage }))
                : []
        };
        const next = updater(draft);
        if (!next) return;
        cache[idx] = { ...current, ...next };
        clamp();
        persist();
        notify();
    }

    function subscribe(listener) {
        if (typeof listener !== 'function') return () => {};
        listeners.add(listener);
        return () => listeners.delete(listener);
    }

    function clear() {
        cache = [];
        persist();
        notify();
    }

    return {
        init,
        getAll: () => getSnapshot(),
        upsert,
        patch,
        subscribe,
        clear
    };
})();

